(() => {
  'use strict';

  const RUNTIME_FLAG = '__lwcsTavernBridgeRuntimeLoaded';
  const LEGACY_FLAG = '__lwcsUiParityRuntimeLoaded';
  const ROOT_ID = 'lwcs-ui-parity-root';
  const STYLE_ID = 'lwcs-ui-parity-style';
  const INLINE_SCRIPT_ID = 'lwcs-ui-parity-inline-script';
  const STYLE_BASE64 = '';
  const BODY_BASE64 = '';
  const INLINE_BASE64 = '';
  const doc = document;
  const loadedScripts = new Map();
  let initPromise = null;

  if (window[RUNTIME_FLAG] || window[LEGACY_FLAG]) {
    try {
      if (window.__lwcsTavernBridgeApi && typeof window.__lwcsTavernBridgeApi.show === 'function') {
        window.__lwcsTavernBridgeApi.show();
      }
    } catch (_) {}
    return;
  }

  window[RUNTIME_FLAG] = true;
  window[LEGACY_FLAG] = true;

  function decodeBase64Unicode(base64) {
    const binary = atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i += 1) {
      bytes[i] = binary.charCodeAt(i);
    }
    return new TextDecoder('utf-8').decode(bytes);
  }

  function getRuntimeScriptUrl() {
    const current = doc.currentScript;
    if (current && current.src) return current.src;
    const scripts = Array.from(doc.scripts || []);
    const hit = scripts.reverse().find(script => script && script.src && /lwcs-tavern-bridge\.runtime\.js(?:\?|$)/.test(script.src));
    return hit ? hit.src : '';
  }

  function resolveAssetUrl(filename) {
    const runtimeScriptUrl = getRuntimeScriptUrl();
    if (!runtimeScriptUrl) return filename;
    try {
      return new URL(filename, runtimeScriptUrl).href;
    } catch (_) {
      return filename;
    }
  }

  function ensureStyle() {
    if (doc.getElementById(STYLE_ID)) return;
    const style = doc.createElement('style');
    style.id = STYLE_ID;
    style.textContent = `
#${ROOT_ID}{position:fixed;inset:0;z-index:2147483000;display:block;overflow:hidden;background:transparent;}
#${ROOT_ID}[data-hidden="1"]{display:none !important;}
` + decodeBase64Unicode(STYLE_BASE64);
    doc.head.appendChild(style);
  }

  function ensureRoot() {
    if (!doc.body) throw new Error('document.body is not ready');
    let root = doc.getElementById(ROOT_ID);
    if (!root) {
      root = doc.createElement('div');
      root.id = ROOT_ID;
      doc.body.appendChild(root);
    }
    return root;
  }

  function ensureMarkup() {
    const root = ensureRoot();
    if (root.dataset.mounted === '1') return root;
    root.innerHTML = decodeBase64Unicode(BODY_BASE64).trim();
    root.dataset.mounted = '1';
    root.dataset.hidden = '0';
    return root;
  }

  function showRoot() {
    const root = ensureRoot();
    root.dataset.hidden = '0';
    const detailModal = doc.getElementById('detailModal');
    if (detailModal) {
      detailModal.style.display = '';
    }
  }

  function hideRoot() {
    const root = doc.getElementById(ROOT_ID);
    if (root) {
      root.dataset.hidden = '1';
    }
    const detailModal = doc.getElementById('detailModal');
    if (detailModal) {
      detailModal.classList.remove('show');
      detailModal.setAttribute('aria-hidden', 'true');
      detailModal.style.display = 'none';
    }
  }

  function destroyRoot() {
    hideRoot();
    const root = doc.getElementById(ROOT_ID);
    if (root) {
      root.remove();
    }
    const detailModal = doc.getElementById('detailModal');
    if (detailModal) {
      detailModal.remove();
    }
    const battleOverlay = doc.getElementById('battle-overlay');
    if (battleOverlay) {
      battleOverlay.remove();
    }
  }

  function loadScriptOnce(key, filename) {
    if (loadedScripts.has(key)) return loadedScripts.get(key);
    const url = resolveAssetUrl(filename);
    const promise = new Promise((resolve, reject) => {
      const existing = doc.querySelector(`script[data-lwcs-script="${key}"]`);
      if (existing) {
        if (existing.dataset.loaded === '1') {
          resolve();
          return;
        }
        existing.addEventListener('load', () => resolve(), { once: true });
        existing.addEventListener('error', () => reject(new Error(`load failed: ${url}`)), { once: true });
        return;
      }
      const script = doc.createElement('script');
      script.src = url;
      script.async = false;
      script.dataset.lwcsScript = key;
      script.addEventListener('load', () => {
        script.dataset.loaded = '1';
        resolve();
      }, { once: true });
      script.addEventListener('error', () => reject(new Error(`load failed: ${url}`)), { once: true });
      doc.body.appendChild(script);
    });
    loadedScripts.set(key, promise);
    return promise;
  }

  function injectInlineScript() {
    if (doc.getElementById(INLINE_SCRIPT_ID)) return;
    const script = doc.createElement('script');
    script.id = INLINE_SCRIPT_ID;
    script.text = decodeBase64Unicode(INLINE_BASE64);
    doc.body.appendChild(script);
  }

  async function init() {
    if (initPromise) return initPromise;
    initPromise = (async () => {
      ensureStyle();
      ensureMarkup();
      await loadScriptOnce('trade', 'https://cdn.jsdelivr.net/gh/sasajyunainui/lwcs@main/lwcs-trade.module.js');
      await loadScriptOnce('profession', 'https://cdn.jsdelivr.net/gh/sasajyunainui/lwcs@main/lwcs-profession.module.js');
      await loadScriptOnce('battle', 'https://cdn.jsdelivr.net/gh/sasajyunainui/lwcs@main/lwcs-battle.module.js');
      injectInlineScript();
      await loadScriptOnce('sheep', 'https://cdn.jsdelivr.net/gh/sasajyunainui/lwcs@main/lwcs-map.js');
      showRoot();
    })().catch(error => {
      initPromise = null;
      throw error;
    });
    return initPromise;
  }

  window.__lwcsTavernBridgeApi = {
    show() {
      return init().then(() => showRoot());
    },
    hide() {
      hideRoot();
    },
    destroy() {
      destroyRoot();
    }
  };

  if (doc.readyState === 'loading') {
    doc.addEventListener('DOMContentLoaded', () => {
      init().catch(error => console.error('[LWCS] runtime init failed', error));
    }, { once: true });
  } else {
    init().catch(error => console.error('[LWCS] runtime init failed', error));
  }
})();
